export async function appendEventLedgerEvent(projectRoot, event) {
  const eventPath = getEventLedgerPath(projectRoot);
  const nextEvent = eventLedgerEventSchema.parse({...event, kind:"fabric-event", ...});
  await ensureParentDirectory(eventPath);
  await appendFile(eventPath, `${JSON.stringify(nextEvent)}\n`, "utf8");
  return nextEvent;
}

